// ==========================================
// 1. DÜĞÜMLERDEN VERİ ÇEKME
// ==========================================
let aiMetin = "";
try { aiMetin = $('Yapay Zeka Analizi').first()?.json?.choices?.[0]?.message?.content || ""; } catch (e) {}

let bistItems = [];
try { bistItems = $('BIST Hesaplayıcı').all().map(i => i.json); } catch (e) {}

let ipoItems = [];
try { ipoItems = $('IPO Hesaplayıcı').all().map(i => i.json); } catch (e) {}

let cryptoItems = [];
try { cryptoItems = $('Kripto Hesaplayıcı').all().map(i => i.json); } catch (e) {}

let metalItems = [];
try { metalItems = $('Maden Hesaplayıcı').first()?.json?.metals || []; } catch (e) {}

const renderTd = (val) => {
  const color = val >= 0 ? '#27ae60' : '#e74c3c';
  const sign = val > 0 ? '+' : '';
  return `<td style="padding: 6px 8px; color: ${color}; font-weight: bold;">%${sign}${val}</td>`;
};

// ==========================================
// 2. HTML TABLOLARI (GÜNLÜK, HAFTALIK, AYLIK, 3 AYLIK, YILLIK)
// ==========================================

let aiHtml = aiMetin ? `
  <div style="background-color: #f4f9f4; border-left: 4px solid #2ecc71; padding: 15px; margin-bottom: 20px; border-radius: 4px; line-height: 1.6;">
    <span style="font-size: 16px; font-weight: bold; color: #27ae60; display: block; margin-bottom: 8px;">🤖 Yapay Zeka Teknik Analiz Raporu</span>
    <p style="margin: 0; font-size: 13px; color: #2c3e50; white-space: pre-line; font-family: Arial, sans-serif;">${aiMetin}</p>
  </div>` : "";

// Değerli Madenler Tablosu
let metalHtml = "";
if (metalItems.length > 0) {
  metalHtml = `
    <div style="margin-top: 20px; background-color: #ffffff; border: 1px solid #e2e8f0; border-radius: 6px; padding: 12px; font-family: Arial, sans-serif;">
      <span style="font-size: 15px; font-weight: bold; color: #1e293b; display: block; margin-bottom: 8px; border-bottom: 2px solid #eab308; padding-bottom: 4px;">🏆 Değerli Madenler & Döviz</span>
      <table style="width: 100%; border-collapse: collapse; font-size: 12px; text-align: left;">
        <thead>
          <tr style="background-color: #f8fafc; color: #475569;">
            <th style="padding: 6px 8px;">Varlık</th>
            <th style="padding: 6px 8px;">Fiyat</th>
            <th style="padding: 6px 8px;">Günlük</th>
            <th style="padding: 6px 8px;">Haftalık</th>
            <th style="padding: 6px 8px;">Aylık</th>
            <th style="padding: 6px 8px;">3 Aylık</th>
            <th style="padding: 6px 8px;">Yıllık</th>
          </tr>
        </thead>
        <tbody>`;
  metalItems.forEach(m => {
    metalHtml += `
      <tr style="border-bottom: 1px solid #f1f5f9;">
        <td style="padding: 6px 8px;"><b>${m.name}</b></td>
        <td style="padding: 6px 8px;">${m.price}</td>
        ${renderTd(m.dailyChange)}
        ${renderTd(m.weeklyChange)}
        ${renderTd(m.monthlyChange)}
        ${renderTd(m.threeMonthChange)}
        ${renderTd(m.yearlyChange)}
      </tr>`;
  });
  metalHtml += `</tbody></table></div>`;
}

// Kripto Para Tablosu
let cryptoHtml = "";
if (cryptoItems.length > 0) {
  cryptoHtml = `
    <div style="margin-top: 20px; background-color: #ffffff; border: 1px solid #e2e8f0; border-radius: 6px; padding: 12px; font-family: Arial, sans-serif;">
      <span style="font-size: 15px; font-weight: bold; color: #1e293b; display: block; margin-bottom: 8px; border-bottom: 2px solid #f59e0b; padding-bottom: 4px;">🪙 Kripto Para Piyasası</span>
      <table style="width: 100%; border-collapse: collapse; font-size: 12px; text-align: left;">
        <thead>
          <tr style="background-color: #f8fafc; color: #475569;">
            <th style="padding: 6px 8px;">Varlık</th>
            <th style="padding: 6px 8px;">Fiyat ($)</th>
            <th style="padding: 6px 8px;">Günlük</th>
            <th style="padding: 6px 8px;">Haftalık</th>
            <th style="padding: 6px 8px;">Aylık</th>
            <th style="padding: 6px 8px;">3 Aylık</th>
            <th style="padding: 6px 8px;">Yıllık</th>
          </tr>
        </thead>
        <tbody>`;
  cryptoItems.forEach(c => {
    cryptoHtml += `
      <tr style="border-bottom: 1px solid #f1f5f9;">
        <td style="padding: 6px 8px;"><b>${c.name}</b></td>
        <td style="padding: 6px 8px;">$${c.priceUsd}</td>
        ${renderTd(c.dailyChange)}
        ${renderTd(c.weeklyChange)}
        ${renderTd(c.monthlyChange)}
        ${renderTd(c.threeMonthChange)}
        ${renderTd(c.yearlyChange)}
      </tr>`;
  });
  cryptoHtml += `</tbody></table></div>`;
}

// BIST Hisse Tablosu
let bistHtml = "";
if (bistItems.length > 0) {
  bistHtml = `
    <div style="margin-top: 20px; background-color: #ffffff; border: 1px solid #e2e8f0; border-radius: 6px; padding: 12px; font-family: Arial, sans-serif;">
      <span style="font-size: 15px; font-weight: bold; color: #1e293b; display: block; margin-bottom: 8px; border-bottom: 2px solid #3b82f6; padding-bottom: 4px;">📈 BIST Hisse Portföyü</span>
      <table style="width: 100%; border-collapse: collapse; font-size: 12px; text-align: left;">
        <thead>
          <tr style="background-color: #f8fafc; color: #475569;">
            <th style="padding: 6px 8px;">Hisse</th>
            <th style="padding: 6px 8px;">Son Fiyat</th>
