            <th style="padding: 6px 8px;">Haftalık</th>
            <th style="padding: 6px 8px;">Aylık</th>
            <th style="padding: 6px 8px;">3 Aylık</th>
            <th style="padding: 6px 8px;">Yıllık</th>
          </tr>
        </thead>
        <tbody>`;
  bistItems.forEach(b => {
    bistHtml += `
      <tr style="border-bottom: 1px solid #f1f5f9;">
        <td style="padding: 6px 8px;"><b>${b.name}</b> (${b.symbol})</td>
        <td style="padding: 6px 8px;">₺${b.currentPrice}</td>
        ${renderTd(b.dailyChange)}
        ${renderTd(b.weeklyChange)}
        ${renderTd(b.monthlyChange)}
        ${renderTd(b.threeMonthChange)}
        ${renderTd(b.yearlyChange)}
