}

// Halka Arz Tablosu
let ipoHtml = "";
if (ipoItems.length > 0) {
  ipoHtml = `
    <div style="margin-top: 20px; background-color: #ffffff; border: 1px solid #e2e8f0; border-radius: 6px; padding: 12px; font-family: Arial, sans-serif;">
      <span style="font-size: 15px; font-weight: bold; color: #1e293b; display: block; margin-bottom: 8px; border-bottom: 2px solid #10b981; padding-bottom: 4px;">🚀 Son 5 Halka Arz Performansı</span>
      <table style="width: 100%; border-collapse: collapse; font-size: 12px; text-align: left;">
        <thead>
          <tr style="background-color: #f8fafc; color: #475569;">
            <th style="padding: 6px 8px;">Şirket</th>
            <th style="padding: 6px 8px;">Son Fiyat</th>
            <th style="padding: 6px 8px;">Günlük</th>
            <th style="padding: 6px 8px;">Haftalık</th>
            <th style="padding: 6px 8px;">Toplam Getiri</th>
          </tr>
        </thead>
        <tbody>`;
  ipoItems.forEach(i => {
    ipoHtml += `
      <tr style="border-bottom: 1px solid #f1f5f9;">
        <td style="padding: 6px 8px;"><b>${i.name}</b> (${i.symbol})</td>
        <td style="padding: 6px 8px;">₺${i.currentPrice}</td>
        ${renderTd(i.dailyChange)}
        ${renderTd(i.weeklyChange)}
        ${renderTd(i.totalReturn)}
      </tr>`;
  });
  ipoHtml += `</tbody></table></div>`;
}

// Final HTML
let finalHtml = `
<!DOCTYPE html>
<html>
<head><meta charset="utf-8"></head>
<body style="margin: 0; padding: 0; font-family: Arial, sans-serif; color: #333; background-color: #ffffff;">
  <div style="max-width: 700px; margin: 0 auto; padding: 10px;">
    ${aiHtml}
    ${metalHtml}
    ${cryptoHtml}
    ${bistHtml}
    ${ipoHtml}
  </div>
</body>
</html>`;

const safeHtml = finalHtml
  .replace(/ç/g, '&#231;').replace(/Ç/g, '&#199;')
  .replace(/ğ/g, '&#287;').replace(/Ğ/g, '&#286;')
  .replace(/ı/g, '&#305;').replace(/İ/g, '&#304;')
  .replace(/ö/g, '&#246;').replace(/Ö/g, '&#214;')
  .replace(/ş/g, '&#351;').replace(/Ş/g, '&#350;')
  .replace(/ü/g, '&#252;').replace(/Ü/g, '&#220;');

return [{ json: { html_body: safeHtml } }];

const inputJson = $input.first().json;
let rawHtml = inputJson.data || inputJson.body || (typeof inputJson === 'string' ? inputJson : JSON.stringify(inputJson));

function fixTurkishText(str) {
  if (!str) return "";
  let text = str.replace(/<[^>]+>/g, '').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&quot;/g, '"');
  const map = {
    '脟': 'Ç', 'Ã‡': 'Ç', '脧': 'Ç', '莽': 'ç', 'Ã§': 'ç',
    '脛臑': 'Ğ', 'ÄĞ': 'Ğ', '脛鸥': 'ğ', 'ÄŸ': 'ğ',
    '脛脛': 'İ', 'Ä°': 'İ', '陌': 'İ', '脛卤': 'ı', 'Ä±': 'ı', '谋': 'ı',
    '脰': 'Ö', 'Ã–': 'Ö', '枚': 'ö', 'Ã¶': 'ö',
    '艦': 'Ş', 'Åž': 'Ş', '艧': 'ş', 'ÅŸ': 'ş',
    '脺': 'Ü', 'Ãœ': 'Ü', '眉': 'ü', 'Ã¼': 'ü', 'ï¿½': ''
  };
  for (const [bad, good] of Object.entries(map)) {
    text = text.split(bad).join(good);
  }
  return text.trim();
}

const extractedIpos = [];
const seenSymbols = new Set();
const articleRegex = /<article[^>]*class=["'][^"']*index-list[^"']*["'][^>]*>(.*?)<\/article>/gis;

let match;

while ((match = articleRegex.exec(rawHtml)) !== null) {
  const blockHtml = match[1];

  // A. BIST Kodu
  const bistMatch = blockHtml.match(/class=["'][^"']*il-bist-kod[^"']*["'][^>]*>\s*([A-Z0-9]{3,6})\s*<\/span>/i);
  if (!bistMatch) continue;
  const symbol = bistMatch[1].trim();

  // B. Rozet Filtresi
  const hasNewClass = blockHtml.includes('il-new') || /class=["'][^"']*il-new[^"']*["']/i.test(blockHtml);
  const blockTextLower = blockHtml.toLowerCase();

  const isPending = hasNewClass || 
                    blockTextLower.includes('yeni!') || 
                    blockTextLower.includes('il-tt') || 
                    blockTextLower.includes('talep toplan') || 
                    blockTextLower.includes('taslak') || 
                    blockTextLower.includes('spk');

  if (isPending) continue;

  // C. Şirket Adı
  let companyName = "";
  const nameMatch = blockHtml.match(/class=["'][^"']*il-halka-arz-sirket[^"']*["'][^>]*>(.*?)<\/h3>/i);
  if (nameMatch) {
    companyName = nameMatch[1];
  } else {
    const titleAttrMatch = blockHtml.match(/title=["']([^"']+)["']/i);
    if (titleAttrMatch) companyName = titleAttrMatch[1];
  }
  companyName = fixTurkishText(companyName);

  // D. Detay Sayfası Linki
  const urlMatch = blockHtml.match(/href=["']([^"']+)["']/i);
  const url = urlMatch ? urlMatch[1] : "";

  if (symbol && !seenSymbols.has(symbol) && /^[A-Z0-9]{3,6}$/.test(symbol)) {
    seenSymbols.add(symbol);
    extractedIpos.push({
      symbol: `${symbol}.IS`,
      name: companyName || symbol,
      url: url,
      status: "İşlem Gören"
    });
  }

  if (extractedIpos.length === 5) break;
}

return extractedIpos.map(ipo => ({ json: ipo }));

const results = [];
const items = $input.all();

// 1. Detay sayfalarından (IPO Detay Fetch) orijinal halka arz fiyatlarını okuyoruz
const detailItems = $('IPO Detay Fetch').all();
const scraperItems = $('Halka Arz Kazıyıcı').all();

const infoMap = {};

scraperItems.forEach((scItem, idx) => {
  const symbol = scItem.json.symbol;
  const detailHtml = detailItems[idx]?.json?.data || detailItems[idx]?.json?.body || "";

  let ipoPrice = 0;
  const priceMatch = 
    detailHtml.match(/Halka\s*Arz\s*Fiyat[ıi\/]*[\s\S]*?<strong[^>]*>\s*([0-9]{1,4}[.,][0-9]{2})\s*(?:TL|₺)\s*<\/strong>/i) ||
    detailHtml.match(/<strong[^>]*class=["'][^"']*f700[^"']*["'][^>]*>\s*([0-9]{1,4}[.,][0-9]{2})\s*(?:TL|₺)\s*<\/strong>/i) ||
    detailHtml.match(/([0-9]{1,4}[.,][0-9]{2})\s*(?:TL|₺)/i);

  if (priceMatch) {
    ipoPrice = parseFloat(priceMatch[1].replace(/\./g, '').replace(',', '.'));
  }

  infoMap[symbol] = {
    name: scItem.json.name,
    ipoPrice: ipoPrice
  };
});

// 2. Yahoo Finance verileriyle kesin 5 iş günü hesaplaması yapıyoruz
for (const item of items) {
  const yahooData = item.json;
  const chartResult = yahooData.chart?.result?.[0];

  if (!chartResult) continue;

  const fullSymbol = chartResult.meta.symbol;
  const cleanSymbol = fullSymbol.replace('.IS', '');
  const companyInfo = infoMap[fullSymbol] || { name: cleanSymbol, ipoPrice: 0 };

  const rawQuotes = chartResult.indicators?.quote?.[0]?.close || [];
  const cleanQuotes = rawQuotes.filter(p => p !== null && p !== undefined);

  if (cleanQuotes.length === 0) continue;

  const currentPrice = chartResult.meta.regularMarketPrice || cleanQuotes[cleanQuotes.length - 1];

  // A. GÜNLÜK DEĞİŞİM (%) - BIST %10 Tavan/Taban Limitli
  let prevClose = cleanQuotes.length >= 2 ? cleanQuotes[cleanQuotes.length - 2] : (chartResult.meta.chartPreviousClose || currentPrice);
  let dailyChange = prevClose > 0 && prevClose !== currentPrice ? ((currentPrice - prevClose) / prevClose) * 100 : 0;

  if (dailyChange > 10) dailyChange = 10.00;
  if (dailyChange < -10) dailyChange = -10.00;

  // B. HAFTALIK DEĞİŞİM (%) - Kesin Olarak "Son 5 İş Günü" (5 Seans Önceki Kapanış vs Bugün)
  let weeklyChange = 0;
  if (cleanQuotes.length >= 6) {
    // Bugün (cleanQuotes.length - 1) ile TAM 5 İŞ GÜNÜ ÖNCEKİ (cleanQuotes.length - 6) kapanış karşılaştırılır
    const fiveTradingDaysAgoPrice = cleanQuotes[cleanQuotes.length - 6];
    weeklyChange = fiveTradingDaysAgoPrice > 0 ? ((currentPrice - fiveTradingDaysAgoPrice) / fiveTradingDaysAgoPrice) * 100 : 0;
  } else {
    // Eğer hisse henüz 5 iş gününden az süredir borsa ortamında işlem görüyorsa: İlk Borsa Günü Kapanışı -> Bugün
    const firstDayPrice = cleanQuotes[0];
    weeklyChange = firstDayPrice > 0 ? ((currentPrice - firstDayPrice) / firstDayPrice) * 100 : 0;
  }

  // C. TOPLAM GETİRİ (%): Orijinal Halka Arz Fiyatından (Örn: 70,00 TL) Hesaplama
  let totalReturn = 0;
  const basePrice = companyInfo.ipoPrice > 0 ? companyInfo.ipoPrice : cleanQuotes[0];
  if (basePrice > 0) {
    totalReturn = ((currentPrice - basePrice) / basePrice) * 100;
  }

  results.push({
    json: {
      symbol: cleanSymbol,
      name: companyInfo.name,
      ipoPrice: companyInfo.ipoPrice,
      currentPrice: Number(currentPrice.toFixed(2)),
      dailyChange: Number(dailyChange.toFixed(2)),
      weeklyChange: Number(weeklyChange.toFixed(2)),
      totalReturn: Number(totalReturn.toFixed(2)),
      tradingDays: cleanQuotes.length
    }
  });
}

return results;

// Takip edilecek güncellenmiş BIST portföyü
const bistList = [
  { symbol: "KCHOL.IS", name: "Koç Holding" },
  { symbol: "ASELS.IS", name: "Aselsan" },
  { symbol: "TUPRS.IS", name: "Tüpraş" },
  { symbol: "SAHOL.IS", name: "Sabancı Holding" },
  { symbol: "FROTO.IS", name: "Ford Otosan" },
  { symbol: "PGSUS.IS", name: "Pegasus" },
  { symbol: "THYAO.IS", name: "Türk Hava Yolları" },
  { symbol: "EREGL.IS", name: "Ereğli Demir Çelik" },
  { symbol: "ASTOR.IS", name: "Astor Enerji" }
];

return bistList.map(stock => ({ json: stock }));

const results = [];
const items = $input.all();
const listItems = $('BIST Liste').all();

const nameMap = {};
listItems.forEach(i => { if (i.json.symbol) nameMap[i.json.symbol] = i.json.name; });

for (const item of items) {
  const chartResult = item.json.chart?.result?.[0];
  if (!chartResult) continue;

  const fullSymbol = chartResult.meta.symbol;
  const cleanSymbol = fullSymbol.replace('.IS', '');
  const companyName = nameMap[fullSymbol] || cleanSymbol;

  const rawQuotes = chartResult.indicators?.quote?.[0]?.close || [];
  const cleanQuotes = rawQuotes.filter(p => p !== null && p !== undefined);
  if (cleanQuotes.length === 0) continue;

const currentPrice = chartResult.meta.regularMarketPrice || cleanQuotes[cleanQuotes.length - 1];
  const p1d = cleanQuotes.length >= 2 ? cleanQuotes[cleanQuotes.length - 2] : currentPrice;
  const p5d = cleanQuotes.length >= 6 ? cleanQuotes[cleanQuotes.length - 6] : cleanQuotes[0];
  const p21d = cleanQuotes.length >= 22 ? cleanQuotes[cleanQuotes.length - 22] : cleanQuotes[0];
  const p63d = cleanQuotes.length >= 64 ? cleanQuotes[cleanQuotes.length - 64] : cleanQuotes[0];
  const p252d = cleanQuotes.length >= 253 ? cleanQuotes[cleanQuotes.length - 253] : cleanQuotes[0];

  const getPct = (c, p) => p > 0 ? Number((((c - p) / p) * 100).toFixed(2)) : 0;

  results.push({
    json: {
      symbol: cleanSymbol,
      name: companyName,
      currentPrice: Number(currentPrice.toFixed(2)),
      dailyChange: getPct(currentPrice, p1d),
      weeklyChange: getPct(currentPrice, p5d),
      monthlyChange: getPct(currentPrice, p21d),
      threeMonthChange: getPct(currentPrice, p63d),
      yearlyChange: getPct(currentPrice, p252d)
    }
  });
}

return results;

const cryptoList = [
  { symbol: "BTCUSDT", name: "Bitcoin (BTC)" },
  { symbol: "ETHUSDT", name: "Ethereum (ETH)" },
  { symbol: "SOLUSDT", name: "Solana (SOL)" },
  { symbol: "XRPUSDT", name: "Ripple (XRP)" },
  { symbol: "MMTUSDT", name: "MMT" },
  { symbol: "EIGENUSDT", name: "EigenLayer (EIGEN)" }
];

return cryptoList.map(item => ({ json: item }));

const results = [];
const items = $input.all();
const cryptoList = $('Kripto Liste').all();

for (let i = 0; i < cryptoList.length; i++) {
  const listInfo = cryptoList[i]?.json || {};
  const originalSymbol = listInfo.symbol || "";
  const name = listInfo.name || originalSymbol;

  let klines = [];
  try {
    const rawData = items[i]?.json?.data || items[i]?.json?.body || items[i]?.json;
    if (typeof rawData === 'string') klines = JSON.parse(rawData);
    else if (Array.isArray(rawData)) klines = rawData;
  } catch (e) { klines = []; }

  if (!Array.isArray(klines) || klines.length === 0 || !Array.isArray(klines[0])) continue;

  const currentPrice = parseFloat(klines[klines.length - 1][4] || 0);
  const price1d = parseFloat(klines[Math.max(0, klines.length - 2)][4] || currentPrice);
  const price7d = parseFloat(klines[Math.max(0, klines.length - 8)][4] || currentPrice);
  const price30d = parseFloat(klines[Math.max(0, klines.length - 31)][4] || currentPrice);
  const price90d = parseFloat(klines[Math.max(0, klines.length - 91)][4] || currentPrice);
  const price365d = parseFloat(klines[0][4] || currentPrice);

  const getPct = (c, p) => p > 0 ? Number((((c - p) / p) * 100).toFixed(2)) : 0;
  const formattedPrice = currentPrice >= 1 ? currentPrice.toFixed(2) : currentPrice.toFixed(4);

  results.push({
    json: {
      symbol: originalSymbol.replace('USDT', ''),
      name: name,
      priceUsd: Number(formattedPrice),
      dailyChange: getPct(currentPrice, price1d),
      weeklyChange: getPct(currentPrice, price7d),
      monthlyChange: getPct(currentPrice, price30d),
      threeMonthChange: getPct(currentPrice, price90d),
      yearlyChange: getPct(currentPrice, price365d)
    }
  });
}

return results;

const metalList = [
  { symbol: "GC=F", name: "Ons Altın ($)" },
  { symbol: "SI=F", name: "Ons Gümüş ($)" },
  { symbol: "USDTRY=X", name: "Dolar/TL" }
];

return metalList.map(item => ({ json: item }));

const items = $input.all();
let dataStore = {};

for (const item of items) {
  const chart = item.json.chart?.result?.[0];
  if (!chart) continue;

  const symbol = chart.meta.symbol;
  const quotes = (chart.indicators?.quote?.[0]?.close || []).filter(p => p !== null && p !== undefined);
  if (quotes.length === 0) continue;

  const curr = chart.meta.regularMarketPrice || quotes[quotes.length - 1];
  const p1d = quotes.length >= 2 ? quotes[quotes.length - 2] : curr;
  const p5d = quotes.length >= 6 ? quotes[quotes.length - 6] : quotes[0];
  const p21d = quotes.length >= 22 ? quotes[quotes.length - 22] : quotes[0];
  const p63d = quotes.length >= 64 ? quotes[quotes.length - 64] : quotes[0];
  const p252d = quotes.length >= 253 ? quotes[quotes.length - 253] : quotes[0];

  dataStore[symbol] = { curr, p1d, p5d, p21d, p63d, p252d };
}

const gold = dataStore["GC=F"] || {};
const silver = dataStore["SI=F"] || {};
const usd = dataStore["USDTRY=X"] || {};

const ONS_GRAM = 31.1034768;

const calcGram = (metal, rate) => (metal / ONS_GRAM) * rate;

const gGoldCurr = calcGram(gold.curr || 0, usd.curr || 0);
const gGold1d = calcGram(gold.p1d || 0, usd.p1d || 0);
const gGold5d = calcGram(gold.p5d || 0, usd.p5d || 0);
const gGold21d = calcGram(gold.p21d || 0, usd.p21d || 0);
const gGold63d = calcGram(gold.p63d || 0, usd.p63d || 0);
const gGold252d = calcGram(gold.p252d || 0, usd.p252d || 0);

const gSilverCurr = calcGram(silver.curr || 0, usd.curr || 0);
const gSilver1d = calcGram(silver.p1d || 0, usd.p1d || 0);
const gSilver5d = calcGram(silver.p5d || 0, usd.p5d || 0);
const gSilver21d = calcGram(silver.p21d || 0, usd.p21d || 0);
